// menu.js
// menu.js
import { useState, useEffect } from "react";

export default function Menu() {
  const texts = ["مرحباً بكم", "أهلاً وسهلاً", "تفضلوا", "استمتعوا"];
  const [index, setIndex] = useState(0);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png", top: "15%", left: "3%" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png", top: "35%", left: "2%" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png", top: "55%", right: "3%", left: "auto" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png", top: "75%", right: "2%", left: "auto" },
    { id: 5, name: "قهوة", icon: "☕", color: "#cd6133", image: "https://cdn-icons-png.flaticon.com/512/924/924514.png", top: "20%", right: "4%", left: "auto" },
    { id: 6, name: "عصائر", icon: "🍹", color: "#218c74", image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png", top: "65%", left: "4%" }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 30,
        y: (e.clientY / window.innerHeight - 0.5) * 30
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #0f0c29, #302b63, #24243e)",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* خلفية متحركة */}
      <div style={{
        position: "absolute",
        width: "100%",
        height: "100%",
        background: "radial-gradient(circle at 50% 50%, rgba(34,197,94,0.15) 0%, transparent 70%)",
        pointerEvents: "none"
      }}></div>

      {/* الكاردات موزعين بشكل عشوائي وجميل */}
      {cards.map((card) => (
        <div
          key={card.id}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            transform: `translate(${mousePosition.x * (card.id % 2 === 0 ? 0.8 : -0.5)}px, ${mousePosition.y * (card.id % 2 === 0 ? -0.6 : 0.7)}px)`,
            transition: "transform 0.15s ease-out",
            zIndex: 10,
            cursor: "pointer"
          }}
        >
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}aa)`,
            width: "110px",
            padding: "18px 12px",
            borderRadius: "25px",
            textAlign: "center",
            boxShadow: "0 15px 35px rgba(0,0,0,0.3)",
            backdropFilter: "blur(10px)",
            border: "1px solid rgba(255,255,255,0.25)",
            transition: "all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = "scale(1.15) rotate(5deg)";
            e.currentTarget.style.boxShadow = "0 25px 45px rgba(0,0,0,0.4)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 15px 35px rgba(0,0,0,0.3)";
          }}
          >
            <img src={card.image} alt={card.name} style={{ width: "50px", height: "50px", marginBottom: "8px", filter: "drop-shadow(2px 4px 6px black)" }} />
            <h3 style={{ color: "white", margin: "5px 0", fontSize: "1rem", fontWeight: "bold" }}>{card.name}</h3>
            <span style={{ fontSize: "1.8rem" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* القائمة في المنتصف */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.2}px, ${mousePosition.y * 0.2}px)`,
        textAlign: "center",
        zIndex: 20,
        transition: "transform 0.15s ease-out"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.55)",
          backdropFilter: "blur(25px)",
          padding: "45px 70px",
          borderRadius: "50px",
          border: "2px solid rgba(34,197,94,0.6)",
          boxShadow: "0 0 60px rgba(34,197,94,0.25), 0 20px 40px rgba(0,0,0,0.3)"
        }}>
          <h1 style={{
            fontSize: "3.8rem",
            fontWeight: "bold",
            background: "linear-gradient(135deg, #ffffff, #22c55e, #4ade80)",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            margin: 0,
            letterSpacing: "2px"
          }}>
            {texts[index]}
          </h1>
          <p style={{ color: "#ddd", marginTop: "15px", fontSize: "1.1rem", letterSpacing: "1px" }}>
            ✨ اكتشف قائمتنا ✨
          </p>
          <div style={{
            width: "60px",
            height: "3px",
            background: "linear-gradient(90deg, #22c55e, transparent)",
            margin: "20px auto 0",
            borderRadius: "10px"
          }}></div>
        </div>
      </div>

      {/* عناصر زخرفية */}
      <div style={{
        position: "fixed",
        bottom: "30px",
        left: "30px",
        color: "rgba(255,255,255,0.3)",
        fontSize: "12px",
        zIndex: 30,
        fontStyle: "italic"
      }}>
        ✨ حرك الماوس ✨
      </div>

      <div style={{
        position: "fixed",
        bottom: "30px",
        right: "30px",
        width: "100px",
        height: "100px",
        borderRadius: "50%",
        background: "radial-gradient(circle, rgba(34,197,94,0.15), transparent)",
        pointerEvents: "none",
        zIndex: 0
      }}></div>
    </div>
  );
}
